## 2) 内核：`handle=M -> binder_ref -> binder_node`

### 2.1 通过 handle 在 `refs_by_desc` 找 `binder_ref`

`binder_get_ref_olocked()`（红黑树查找）：

```1208:1229:kernel-6.1/drivers/android/binder.c
static struct binder_ref *binder_get_ref_olocked(struct binder_proc *proc,
						 u32 desc, bool need_strong_ref)
{
	struct rb_node *n = proc->refs_by_desc.rb_node;
	struct binder_ref *ref;

	while (n) {
		ref = rb_entry(n, struct binder_ref, rb_node_desc);

		if (desc < ref->data.desc) {
			n = n->rb_left;
		} else if (desc > ref->data.desc) {
			n = n->rb_right;
		} else if (need_strong_ref && !ref->data.strong) {
			binder_user_error("tried to use weak ref as strong ref\n");
			return NULL;
		} else {
			return ref;
		}
	}
	return NULL;
}
```

### 2.2 从 `binder_ref` 取出 `binder_node`

`binder_get_node_from_ref()`：

```1441:1468:kernel-6.1/drivers/android/binder.c
static struct binder_node *binder_get_node_from_ref(
		struct binder_proc *proc,
		u32 desc, bool need_strong_ref,
		struct binder_ref_data *rdata)
{
	struct binder_node *node;
	struct binder_ref *ref;

	binder_proc_lock(proc);
	ref = binder_get_ref_olocked(proc, desc, need_strong_ref);
	if (!ref)
		goto err_no_ref;
	node = ref->node;
	// ... tmpref ...
	binder_proc_unlock(proc);

	return node;
err_no_ref:
